def handle_status(code):
    if 200 <= code < 300:
        return "ok"
    if code == 400:
        return "client_error"
    if code >= 500:
        return "server_error"
    return "other"

for c in [200, 400, 503]:
    print(c, handle_status(c))

def pages(total=5, size=2):
    for page in range(1, (total + size - 1) // size + 1):
        yield page, list(range((page-1)*size, min(page*size, total)))

for p, items in pages():
    print("page", p, items)

import time
def backoff(attempt, base=0.1):
    return base * (2 ** attempt)

for i in range(3):
    print("sleep", backoff(i))

