def with_fallback(primary, secondary):
    try:
        if primary is None:
            raise RuntimeError("primary down")
        return primary
    except RuntimeError:
        return secondary

print(with_fallback(None, {"lat": 0, "lon": 0}))

import re
def normalize_address(s):
    s = " ".join(s.strip().split())
    return s.title()

print(normalize_address("  av. larco  123 "))

class MockGeocoder:
    def geocode(self, address):
        return {"lat": -12.04, "lon": -77.04, "source": "mock", "query": address}

g = MockGeocoder()
print(g.geocode("Lima"))

ALLOWED = {"address", "city", "country"}
def allowed_for_public_geocoder(payload):
    return set(payload) <= ALLOWED and "document_id" not in payload

print(allowed_for_public_geocoder({"address": "x", "city": "Lima"}))
print(allowed_for_public_geocoder({"address": "x", "document_id": "DNI"}))

def valid_lat_lon(lat, lon):
    return -90 <= lat <= 90 and -180 <= lon <= 180

print(valid_lat_lon(-12.04, -77.04), valid_lat_lon(100, 0))

